SELECT AVG(TIMESTAMPDIFF(HOUR, order_placement_time, shipment_confirmation_time)) AS average_hours
FROM orders
WHERE order_type = 'domestic' AND MONTH(order_placement_time) = MONTH(CURRENT_DATE - INTERVAL 1 MONTH) AND YEAR(order_placement_time) = YEAR(CURRENT_DATE - INTERVAL 1 MONTH);

WITH merged_orders AS (
    SELECT MIN(order_id) AS order_id, external_reference_number, SUM(amount) AS total_amount
    FROM orders
    GROUP BY external_reference_number
) 
DELETE FROM orders 
WHERE order_id NOT IN (SELECT order_id FROM merged_orders);

INSERT INTO orders (order_id, external_reference_number, amount)
SELECT order_id, external_reference_number, total_amount
FROM merged_orders;
